#include<bits/stdc++.h>
using namespace std;
int t,n,a[105],f[25005];
int main()
{
	cin>>t;
	while(t--)
	{
		cin>>n;
		for(int i=1;i<=n;i++) cin>>a[i];
		sort(a+1,a+1+n);
		int ans=0;
		memset(f,0,sizeof(f));
		f[0]=1;
		for(int i=1;i<=n;i++)
		{
			if(f[a[i]]) ans++;
			else
			{
				for(int j=a[i];j<=a[n];j++)
				{
					f[j]=f[j]|f[j-a[i]]; 
				}
			}
		}
		cout<<n-ans<<'\n';
	}
	return 0;
}
